// frontend/src/pages/AuthPage.js
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const styles = {
  page: {
    minHeight: '100vh', display: 'flex', alignItems: 'center',
    justifyContent: 'center', background: 'linear-gradient(135deg, #e8f5f0 0%, #f0f4ff 100%)',
    padding: '20px',
  },
  card: {
    background: '#fff', borderRadius: '20px', padding: '40px',
    width: '100%', maxWidth: '420px',
    boxShadow: '0 4px 24px rgba(0,0,0,0.08)',
  },
  logo: {
    textAlign: 'center', marginBottom: '28px',
  },
  logoText: {
    fontSize: '28px', fontWeight: '700', color: '#1a1a2e',
  },
  logoAccent: { color: '#1D9E75' },
  tagline: { fontSize: '13px', color: '#888', marginTop: '4px' },
  tabRow: {
    display: 'flex', background: '#f4f4f4', borderRadius: '10px',
    padding: '4px', marginBottom: '24px',
  },
  tab: {
    flex: 1, padding: '10px', textAlign: 'center', border: 'none',
    background: 'transparent', borderRadius: '8px', fontSize: '14px',
    fontWeight: '500', color: '#888', cursor: 'pointer', transition: 'all .2s',
  },
  tabActive: {
    background: '#fff', color: '#1a1a2e',
    boxShadow: '0 2px 8px rgba(0,0,0,0.08)',
  },
  label: { display: 'block', fontSize: '13px', fontWeight: '500', color: '#555', marginBottom: '6px' },
  input: {
    width: '100%', padding: '12px 14px', border: '1.5px solid #e8e8e8',
    borderRadius: '10px', fontSize: '14px', outline: 'none',
    transition: 'border-color .2s', marginBottom: '16px', color: '#1a1a2e',
  },
  btn: {
    width: '100%', padding: '14px', background: '#1D9E75', color: '#fff',
    border: 'none', borderRadius: '10px', fontSize: '15px', fontWeight: '600',
    cursor: 'pointer', marginTop: '4px', transition: 'background .2s',
  },
  error: {
    background: '#fff0f0', border: '1px solid #ffd0d0', color: '#c0392b',
    borderRadius: '8px', padding: '10px 14px', fontSize: '13px', marginBottom: '16px',
  },
  success: {
    background: '#f0fff6', border: '1px solid #b7ebd0', color: '#0f6e56',
    borderRadius: '8px', padding: '10px 14px', fontSize: '13px', marginBottom: '16px',
  },
};

export default function AuthPage() {
  const [mode, setMode]       = useState('login'); // 'login' | 'register'
  const [name, setName]       = useState('');
  const [email, setEmail]     = useState('');
  const [password, setPass]   = useState('');
  const [error, setError]     = useState('');
  const [loading, setLoading] = useState(false);

  const { login, register } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      if (mode === 'login') {
        await login(email, password);
      } else {
        if (!name.trim()) { setError('Naam bharo'); setLoading(false); return; }
        await register(name, email, password);
      }
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.error || 'Kuch gadbad ho gayi. Dobara try karo.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.card}>
        <div style={styles.logo}>
          <div style={styles.logoText}>Visit<span style={styles.logoAccent}>Wise</span> AI</div>
          <div style={styles.tagline}>Smart Crowd &amp; Cost Prediction</div>
        </div>

        <div style={styles.tabRow}>
          <button
            style={{ ...styles.tab, ...(mode === 'login' ? styles.tabActive : {}) }}
            onClick={() => { setMode('login'); setError(''); }}
          >Login</button>
          <button
            style={{ ...styles.tab, ...(mode === 'register' ? styles.tabActive : {}) }}
            onClick={() => { setMode('register'); setError(''); }}
          >Register</button>
        </div>

        {error && <div style={styles.error}>{error}</div>}

        <form onSubmit={handleSubmit}>
          {mode === 'register' && (
            <div>
              <label style={styles.label}>Aapka Naam</label>
              <input
                style={styles.input} type="text" placeholder="Rahul Sharma"
                value={name} onChange={e => setName(e.target.value)} required
              />
            </div>
          )}
          <div>
            <label style={styles.label}>Email Address</label>
            <input
              style={styles.input} type="email" placeholder="rahul@gmail.com"
              value={email} onChange={e => setEmail(e.target.value)} required
            />
          </div>
          <div>
            <label style={styles.label}>Password</label>
            <input
              style={styles.input} type="password" placeholder="••••••••"
              value={password} onChange={e => setPass(e.target.value)} required
            />
          </div>
          <button style={styles.btn} type="submit" disabled={loading}>
            {loading ? 'Please wait...' : mode === 'login' ? 'Login Karo' : 'Account Banao'}
          </button>
        </form>

        {/* Demo credentials hint */}
        <p style={{ textAlign: 'center', fontSize: '12px', color: '#aaa', marginTop: '20px' }}>
          Demo: Register karke seedha start karo
        </p>
      </div>
    </div>
  );
}
